(function(){var f=document.getElementById("form");if(!f)return;var e=document.getElementById("err");
var k=[97,101,103,105,115,45,112,111,114,116,97,108,58,58,118,49];
function S(){return String.fromCharCode.apply(null,k);}
function H(s){return crypto.subtle.digest("SHA-256",new TextEncoder().encode(s)).then(function(b){return Array.prototype.map.call(new Uint8Array(b),function(x){return("0"+x.toString(16)).slice(-2);}).join("");});}
function bad(){e.textContent="Invalid credentials. Check your details and try again.";}
f.addEventListener("submit",function(ev){ev.preventDefault();
var a=document.getElementById("email").value.trim().toLowerCase(),b=document.getElementById("pass").value;
if(!a||!b){e.textContent="Enter your work email and password.";return;}
if(!(window.crypto&&crypto.subtle)){bad();return;}
H(S()+"|"+a+"|"+b).then(function(h){var t="console-"+h.slice(0,32)+".html";
fetch(t,{method:"GET",cache:"no-store"}).then(function(r){if(r&&r.ok){try{sessionStorage.setItem("aegis_auth","1");}catch(_){}location.href=t;}else bad();}).catch(bad);}).catch(bad);});})();
